<?php
 namespace League\CommonMark\Block\Renderer; use League\CommonMark\Block\Element\AbstractBlock; use League\CommonMark\Block\Element\BlockQuote; use League\CommonMark\ElementRendererInterface; use League\CommonMark\HtmlElement; final class BlockQuoteRenderer implements BlockRendererInterface { public function render(AbstractBlock $block, ElementRendererInterface $htmlRenderer, bool $inTightList = false) { if (!($block instanceof BlockQuote)) { throw new \InvalidArgumentException('Incompatible block type: ' . \get_class($block)); } $attrs = $block->getData('attributes', []); $filling = $htmlRenderer->renderBlocks($block->children()); if ($filling === '') { return new HtmlElement('blockquote', $attrs, $htmlRenderer->getOption('inner_separator', "\n")); } return new HtmlElement( 'blockquote', $attrs, $htmlRenderer->getOption('inner_separator', "\n") . $filling . $htmlRenderer->getOption('inner_separator', "\n") ); } } 